import type {
  UnauthenticatedActionDefinition,
  UnauthenticatedQueryDefinition,
  _Task,
} from "../_types";
import type { Prisma } from "@prisma/client";
import type { Payload, SuperJSONObject } from "wasp/core/serialization";
import type {
  Task,
} from "wasp/entities";
import { create as create_ext } from 'wasp/src/tasks'

type _WaspEntityTagged = _Task
type _WaspEntity = Task

/**
 * PUBLIC API
 */
export declare namespace Tasks {
  export type GetAllQuery<Input extends Payload = never, Output extends Payload = Payload> = UnauthenticatedQueryDefinition<[_WaspEntityTagged], Input, Output>


  export type CreateAction<Input extends Payload = never, Output extends Payload = Payload> = UnauthenticatedActionDefinition<[_WaspEntityTagged], Input, Output>


}

/**
 * PRIVATE API
 *
 * The types with the `Resolved` suffix are the types that are used internally by the Wasp client
 * to implement full-stack type safety.
 */
type GetAllInput = {}
type GetAllOutput = _WaspEntity[]
export type GetAllQueryResolved = Tasks.GetAllQuery<GetAllInput, GetAllOutput>


const _waspCreateAction = create_ext
export type CreateActionResolved = typeof _waspCreateAction

